# Configuration
AWS_REGION = os.environ.get("AWS_REGION", "us-east-1")
S3_BUCKET = os.environ.get("S3_BUCKET", "screenshot-service-bucket")
S3_PREFIX = os.environ.get("S3_PREFIX", "screenshots/")
CHROME_DRIVER_PATH = os.environ.get("CHROME_DRIVER_PATH", "/usr/bin/chromedriver")
CHROME_BINARY_PATH = os.environ.get("CHROME_BINARY_PATH", "/usr/bin/google-chrome")
THUMBNAIL_WIDTH = int(os.environ.get("THUMBNAIL_WIDTH", "600"))
THUMBNAIL_HEIGHT = int(os.environ.get("THUMBNAIL_HEIGHT", "400"))
FULL_SCREENSHOT_WIDTH = int(os.environ.get("FULL_SCREENSHOT_WIDTH", "1920"))
FULL_SCREENSHOT_HEIGHT = int(os.environ.get("FULL_SCREENSHOT_HEIGHT", "1080"))
PAGE_LOAD_TIMEOUT = int(os.environ.get("PAGE_LOAD_TIMEOUT", "30"))
CACHE_EXPIRY_HOURS = int(os.environ.get("CACHE_EXPIRY_HOURS", "24"))
MAX_URL_LENGTH = 2048
ALLOWED_SCHEMES = {"http", "https"}

# Logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Flask app
app = Flask(__name__)

# S3 client
s3_client = boto3.client("s3", region_name=AWS_REGION)


def validate_url(url: str) -> tuple[bool, str]:
    """Validate the provided URL."""
    if not url:
        return False, "URL is required"
    
    if len(url) > MAX_URL_LENGTH:
        return False, f"URL exceeds maximum length of {MAX_URL_LENGTH} characters"
    
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Invalid URL format"
    
    if parsed.scheme not in ALLOWED_SCHEMES:
        return False, f"URL scheme must be one of: {', '.join(ALLOWED_SCHEMES)}"
    
    if not parsed.netloc:
        return False, "URL must have a valid domain"
    
    # Block private/internal IPs (basic SSRF protection)
    hostname = parsed.hostname
    if hostname:
        blocked_hosts = ["localhost", "127.0.0.1", "0.0.0.0", "169.254.169.254", "metadata.google.internal"]
        if hostname in blocked_hosts:
            return False, "URL points to a blocked host"
        if hostname.startswith("10.") or hostname.startswith("192.168.") or hostname.startswith("172."):
            return False, "URL points to a private network"
    
    return True, ""


def generate_cache_key(url: str, width: int, height: int) -> str:
    """Generate a deterministic cache key for a URL + dimensions."""
    key_input = f"{url}_{width}x{height}"
    url_hash = hashlib.sha256(key_input.encode()).hexdigest()
    return url_hash


def get_s3_key(cache_key: str) -> str:
    """Get the S3 object key for a cache key."""
    return f"{S3_PREFIX}{cache_key}.png"


def check_cache(cache_key: str) -> str | None:
    """Check if a screenshot is already cached in S3. Returns the S3 URL if cached."""
    s3_key = get_s3_key(cache_key)
    try:
        response = s3_client.head_object(Bucket=S3_BUCKET, Key=s3_key)
        last_modified = response["LastModified"]
        age_hours = (datetime.now(last_modified.tzinfo) - last_modified).total_seconds() / 3600
        if age_hours < CACHE_EXPIRY_HOURS:
            presigned_url = s3_client.generate_presigned_url(
                "get_object",
                Params={"Bucket": S3_BUCKET, "Key": s3_key},
                ExpiresIn=3600,
            )
            logger.info(f"Cache hit for key: {cache_key}")
            return presigned_url
        else:
            logger.info(f"Cache expired for key: {cache_key}")
            return None
    except ClientError as e:
        if e.response["Error"]["Code"] == "404":
            logger.info(f"Cache miss for key: {cache_key}")
            return None
        raise


def create_chrome_driver() -> webdriver.Chrome:
    """Create and configure a headless Chrome WebDriver instance."""
    chrome_options = Options()
    chrome_options.add_argument("--headless=new")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--disable-extensions")
    chrome_options.add_argument("--disable-plugins")
    chrome_options.add_argument(f"--window-size={FULL_SCREENSHOT_WIDTH},{FULL_SCREENSHOT_HEIGHT}")
    chrome_options.add_argument("--hide-scrollbars")
    chrome_options.add_argument("--mute-audio")
    chrome_options.add_argument("--disable-background-networking")
    chrome_options.add_argument("--disable-default-apps")
    chrome_options.add_argument("--disable-sync")
    chrome_options.add_argument("--disable-translate")
    chrome_options.add_argument("--metrics-recording-only")
    chrome_options.add_argument("--safebrowsing-disable-auto-update")
    chrome_options.add_argument("--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")
    
    if os.path.exists(CHROME_BINARY_PATH):
        chrome_options.binary_location = CHROME_BINARY_PATH
    
    service = Service(CHROME_DRIVER_PATH) if os.path.exists(CHROME_DRIVER_PATH) else Service()
    
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    driver.set_script_timeout(PAGE_LOAD_TIMEOUT)
    
    return driver


def take_screenshot(url: str) -> bytes:
    """Take a full-page screenshot of the given URL."""
    driver = None
    try:
        driver = create_chrome_driver()
        logger.info(f"Navigating to: {url}")
        driver.get(url)
        
        # Wait for page to be in a ready state
        WebDriverWait(driver, PAGE_LOAD_TIMEOUT).until(
            lambda d: d.execute_script("return document.readyState") == "complete"
        )
        
        # Small additional wait for dynamic content
        import time
        time.sleep(2)
        
        screenshot_png = driver.get_screenshot_as_png()
        logger.info(f"Screenshot taken for: {url} ({len(screenshot_png)} bytes)")
        return screenshot_png
        
    except Exception as e:
        logger.error(f"Error taking screenshot of {url}: {str(e)}")
        raise
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass


def create_thumbnail(screenshot_bytes: bytes, width: int, height: int) -> bytes:
    """Create a thumbnail from the full screenshot."""
    image = Image.open(io.BytesIO(screenshot_bytes))
    
    # Calculate crop area to maintain aspect ratio of thumbnail
    target_ratio = width / height
    img_ratio = image.width / image.height
    
    if img_ratio > target_ratio:
        # Image is wider than target; crop sides
        new_width = int(image.height * target_ratio)
        left = (image.width - new_width) // 2
        image = image.crop((left, 0, left + new_width, image.height))
    else:
        # Image is taller than target; crop from top portion
        new_height = int(image.width / target_ratio)
        image = image.crop((0, 0, image.width, new_height))
    
    # Resize to target dimensions
    image = image.resize((width, height), Image.LANCZOS)
    
    # Save to bytes
    output = io.BytesIO()
    image.save(output, format="PNG", optimize=True)
    output.seek(0)
    
    thumbnail_bytes = output.getvalue()
    logger.info(f"Thumbnail created: {width}x{height} ({len(thumbnail_bytes)} bytes)")
    return thumbnail_bytes


def upload_to_s3(image_bytes: bytes, cache_key: str, url: str) -> str:
    """Upload the screenshot to S3 and return a presigned URL."""
    s3_key = get_s3_key(cache_key)
    
    s3_client.put_object(
        Bucket=S3_BUCKET,
        Key=s3_key,
        Body=image_bytes,
        ContentType="image/png",
        Metadata={
            "source_url": url,
            "created_at": datetime.utcnow().isoformat(),
            "cache_key": cache_key,
        },
    )
    
    presigned_url = s3_client.generate_presigned_url(
        "get_object",
        Params={"Bucket": S3_BUCKET, "Key": s3_key},
        ExpiresIn=3600,
    )
    
    logger.info(f"Uploaded to S3: {s3_key}")
    return presigned_url


def ensure_bucket_exists():
    """Ensure the S3 bucket exists, create it if it doesn't."""
    try:
        s3_client.head_bucket(Bucket=S3_BUCKET)
    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code in ("404", "NoSuchBucket"):
            logger.info(f"Creating S3 bucket: {S3_BUCKET}")
            if AWS_REGION == "us-east-1":
                s3_client.create_bucket(Bucket=S3_BUCKET)
            else:
                s3_client.create_bucket(
                    Bucket=S3_BUCKET,
                    CreateBucketConfiguration={"LocationConstraint": AWS_REGION},
                )
            # Block public access
            s3_client.put_public_access_block(
                Bucket=S3_BUCKET,
                PublicAccessBlockConfiguration={
                    "BlockPublicAcls": True,
                    "IgnorePublicAcls": True,
                    "BlockPublicPolicy": True,
                    "RestrictPublicBuckets": True,
                },
            )
            logger.info(f"S3 bucket created: {S3_BUCKET}")
        else:
            raise


