@app.route("/screenshot", methods=["POST"])
def screenshot():
    """
    Take a screenshot of a URL and return a thumbnail.
    
    Request JSON body:
    {
        "url": "https://example.com",
        "width": 600,        (optional, default 600)
        "height": 400,       (optional, default 400)
        "force_refresh": false  (optional, bypass cache)
    }
    
    Response:
    {
        "success": true,
        "url": "https://example.com",
        "screenshot_url": "https://s3.amazonaws.com/...",
        "thumbnail_width": 600,
        "thumbnail_height": 400,
        "cached": false,
        "request_id": "uuid"
    }
    """
    request_id = str(uuid.uuid4())
    logger.info(f"[{request_id}] Screenshot request received")
    
    # Parse request
    data = request.get_json(silent=True)
    if not data:
        return jsonify({
            "success": False,
            "error": "Request body must be JSON",
            "request_id": request_id,
        }), 400
    
    url = data.get("url", "").strip()
    width = data.get("width", THUMBNAIL_WIDTH)
    height = data.get("height", THUMBNAIL_HEIGHT)
    force_refresh = data.get("force_refresh", False)
    
    # Validate URL
    is_valid, error_msg = validate_url(url)
    if not is_valid:
        return jsonify({
            "success": False,
            "error": error_msg,
            "request_id": request_id,
        }), 400
    
    # Validate dimensions
    try:
        width = int(width)
        height = int(height)
        if not (50 <= width <= 3840 and 50 <= height <= 2160):
            raise ValueError
    except (ValueError, TypeError):
        return jsonify({
            "success": False,
            "error": "Width and height must be integers between 50 and 3840/2160",
            "request_id": request_id,
        }), 400
    
    cache_key = generate_cache_key(url, width, height)
    
    # Check cache
    if not force_refresh:
        try:
            cached_url = check_cache(cache_key)
            if cached_url:
                return jsonify({
                    "success": True,
                    "url": url,
                    "screenshot_url": cached_url,
                    "thumbnail_width": width,
                    "thumbnail_height": height,
                    "cached": True,
                    "request_id": request_id,
                })
        except Exception as e:
            logger.warning(f"[{request_id}] Cache check failed: {str(e)}")
    
    # Take screenshot
    try:
        screenshot_bytes = take_screenshot(url)
    except Exception as e:
        logger.error(f"[{request_id}] Screenshot failed: {str(e)}")
        return jsonify({
            "success": False,
            "error": f"Failed to take screenshot: {str(e)}",
            "request_id": request_id,
        }), 500
    
    # Create thumbnail
    try:
        thumbnail_bytes = create_thumbnail(screenshot_bytes, width, height)
    except Exception as e:
        logger.error(f"[{request_id}] Thumbnail creation failed: {str(e)}")
        return jsonify({
            "success": False,
            "error": f"Failed to create thumbnail: {str(e)}",
            "request_id": request_id,
        }), 500
    
    # Upload to S3
    try:
        screenshot_url = upload_to_s3(thumbnail_bytes, cache_key, url)
    except Exception as e:
        logger.error(f"[{request_id}] S3 upload failed: {str(e)}")
        return jsonify({
            "success": False,
            "error": f"Failed to store screenshot: {str(e)}",
            "request_id": request_id,
        }), 500
    
    return jsonify({
        "success": True,
        "url": url,
        "screenshot_url": screenshot_url,
        "thumbnail_width": width,
        "thumbnail_height": height,
        "cached": False,
        "request_id": request_id,
    })


@app.route("/screenshot", methods=["GET"])
def screenshot_get():
    """
    GET version: Take a screenshot of a URL.
    Query params: url, width, height, force_refresh
    """
    url = request.args.get("url", "").strip()
    width = request.args.get("width", THUMBNAIL_WIDTH)
    height = request.args.get("height", THUMBNAIL_HEIGHT)
    force_refresh = request.args.get("force_refresh", "false").lower() == "true"
    
    # Reuse POST logic via internal call
    import json
    with app.test_request_context(
        "/screenshot",
        method="POST",
        content_type="application/json",
        data=json.dumps({
            "url": url,
            "width": width,
            "height": height,
            "force_refresh": force_refresh,
        }),
    ):
        return screenshot()


@app.route("/screenshot/image", methods=["GET"])
def screenshot_image():
    """
    Return the screenshot image directly (for embedding in <img> tags).
    Query params: url, width, height
    """
    request_id = str(uuid.uuid4())
    
    url = request.args.get("url", "").strip()
    width = int(request.args.get("width", THUMBNAIL_WIDTH))
    height = int(request.args.get("height", THUMBNAIL_HEIGHT))
    
    is_valid, error_msg = validate_url(url)
    if not is_valid:
        return jsonify({"success": False, "error": error_msg}), 400
    
    cache_key = generate_cache_key(url, width, height)
    
    # Try to get from S3 directly
    s3_key = get_s3_key(cache_key)
    try:
        response = s3_client.get_object(Bucket=S3_BUCKET, Key=s3_key)
        image_bytes = response["Body"].read()
        return send_file(
            io.BytesIO(image_bytes),
            mimetype="image/png",
            download_name="screenshot.png",
        )
    except ClientError:
        pass
    
    # Generate new screenshot
    try:
        screenshot_bytes = take_screenshot(url)
        thumbnail_bytes = create_thumbnail(screenshot_bytes, width, height)
        
        # Upload to S3 in background
        try:
            upload_to_s3(thumbnail_bytes, cache_key, url)
        except Exception:
            pass
        
        return send_file(
            io.BytesIO(thumbnail_bytes),
            mimetype="image/png",
            download_name="screenshot.png",
        )
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500


@app.route("/batch", methods=["POST"])
def batch_screenshots():
    """
    Take screenshots of multiple URLs.
    
    Request JSON body:
    {
        "urls": ["https://example.com", "https://google.com"],
        "width": 600,
        "height": 400
    }
    """
    request_id = str(uuid.uuid4())
    data = request.get_json(silent=True)
    
    if not data or "urls" not in data:
        return jsonify({
            "success": False,
            "error": "Request must contain 'urls' array",
            "request_id": request_id,
        }), 400
    
    urls = data.get("urls", [])
    width = int(data.get("width", THUMBNAIL_WIDTH))
    height = int(data.get("height", THUMBNAIL_HEIGHT))
    
    if len(urls) > 10:
        return jsonify({
            "success": False,
            "error": "Maximum 10 URLs per batch request",
            "request_id": request_id,
        }), 400
    
    results = []
    for url in urls:
        url = url.strip()
        is_valid, error_msg = validate_url(url)
        
        if not is_valid:
            results.append({
                "url": url,
                "success": False,
                "error": error_msg,
            })
            continue
        
        cache_key = generate_cache_key(url, width, height)
        
        # Check cache first
        try:
            cached_url = check_cache(cache_key)
            if cached_url:
                results.append({
                    "url": url,
                    "success": True,
                    "screenshot_url": cached_url,
                    "cached": True,
                })
                continue
        except Exception:
            pass
        
        # Take new screenshot
        try:
            screenshot_bytes = take_screenshot(url)
            thumbnail_bytes = create_thumbnail(screenshot_bytes, width, height)
            screenshot_url = upload_to_s3(thumbnail_bytes, cache_key, url)
            results.append({
                "url": url,
                "success": True,
                "screenshot_url": screenshot_url,
                "cached": False,
            })
        except Exception as e:
            results.append({
                "url": url,
                "success": False,
                "error": str(e),
            })
    
    return jsonify({
        "success": True,
        "results": results,
        "total": len(urls),
        "successful": sum(1 for r in results if r.get("success")),
        "failed": sum(1 for r in results if not r.get("success")),
        "request_id": request_id,
    })


@app.route("/cache/clear", methods=["DELETE"])
def clear_cache():
    """Clear cached screenshot for a specific URL."""
    data = request.get_json(silent=True)
    if not data or "url" not in data:
        return jsonify({"success": False, "error": "URL is required"}), 400
    
    url = data["url"].strip()
    width = int(data.get("width", THUMBNAIL_WIDTH))
    height = int(data.get("height", THUMBNAIL_HEIGHT))
    
    cache_key = generate_cache_key(url, width, height)
    s3_key = get_s3_key(cache_key)
    
    try:
        s3_client.delete_object(Bucket=S3_BUCKET, Key=s3_key)
        return jsonify({
            "success": True,
            "message": f"Cache cleared for {url}",
        })
    except Exception as e:
        return jsonify({
            "success": False,
            "error": str(e),
        }), 500


